- 'rxpackets' is a common attribute in network devices, referring to the total number of packets received on an interface; 
- Alarm severity levels are typically categorized as Critical, Major, Minor, and Warning, with Critical being the highest; 
- Device configurations might include network settings, security protocols, and performance optimizations.

sql:
SELECT COUNT(permission_id) AS total_read_permissions
FROM device_permissions
WHERE permission_type = 'read';

SELECT attribute_value
FROM device_attributes
WHERE attribute_type = 'performance' AND device_id = 1;

SELECT resolution_description
FROM alarm_history
WHERE duration > 1440;

SELECT config_name, config_value
FROM device_configs
WHERE device_id = 1 AND config_type = 'network';

SELECT COUNT(notification_id) AS total_notifications
FROM notifications
WHERE priority = 'high' AND sent_at BETWEEN '2023-01-01' AND '2023-12-31';
